class AppHealthMonitor {
  static void init() {
    FlutterError.onError = (FlutterErrorDetails details) {
      AppLog.f('FLUTTER', 'Flutter error: ${details.exceptionAsString()}', details.exception, details.stack);
    };

    PlatformDispatcher.instance.onError = (error, stack) {
      AppLog.f('DART', 'Uncaught error: $error', error, stack);
      return true;
    };

    AppLog.i('APP', 'Logging initialized');
  }

  static void reportHeartbeat({required String component, Map<String, Object?>? metrics}) {
    AppLog.d('HEALTH', 'Heartbeat component=$component metrics=${jsonEncode(metrics)}');
  }
}

